#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoJson.h>
#include <Adafruit_SSD1306.h>
#include <DHT.h>
#include <IRremote.h>

// Пиновка
#define MQ2_PIN 34 // ADC1 Channel 6
#define DHT_PIN 4
#define PIR_PIN 5
#define IR_RECV_PIN 15
#define IR_LED_PIN 2
#define OLED_SDA 21
#define OLED_SCL 22

// Настройки WiFi и MQTT
const char* ssid = "YOUR_SSID";
const char* password = "YOUR_PASSWORD";
const char* mqtt_server = "192.168.1.100";
const int mqtt_port = 1883;
const char* mqtt_user = "sensorbox";
const char* mqtt_pass = "your_password";

const char* device_id = "sensorbox_livingroom_01";
const char* topic_telemetry = "home/livingroom/sensorbox_01/telemetry";
const char* topic_status = "home/livingroom/sensorbox_01/status";

// Объекты
WiFiClient espClient;
PubSubClient client(espClient);
Adafruit_SSD1306 display(128, 64, &Wire, -1);
DHT dht(DHT_PIN, DHT22);
IRrecv irrecv(IR_RECV_PIN);
IRsend irsend(IR_LED_PIN);

// Переменные
unsigned long lastMsg = 0;
#define MSG_BUFFER_SIZE (50)
char msg[MSG_BUFFER_SIZE];
uint16_t mq2_baseline = 0;

void setup() {
 Serial.begin(115200);

 // Инициализация дисплея
 if(!display.begin(SSD1306_SWITCHCAPVCC, 0x3C)) {
 Serial.println(F("SSD1306 allocation failed"));
 }
 display.display();
 delay(2000);
 display.clearDisplay();

 // Настройка ADC
 analogReadResolution(12); // 12-bit (0-4095)
 analogSetAttenuation(ADC_11db); // Диапазон 0-3.9V

 // Калибровка MQ-2 (базовое значение в чистом воздухе)
 Serial.println("Calibrating MQ-2... Wait 30 seconds");
 display.setTextSize(1);
 display.setTextColor(SSD1306_WHITE);
 display.setCursor(0,0);
 display.println("Calibrating MQ-2");
 display.display();

 uint32_t sum = 0;
 for(int i=0; i<100; i++) {
 sum += analogRead(MQ2_PIN);
 delay(300);
 }
 mq2_baseline = sum / 100;
 Serial.print("MQ-2 baseline: ");
 Serial.println(mq2_baseline);

 // Инициализация датчиков
 dht.begin();
 irrecv.enableIRIn();
 irsend.begin();

 // Подключение WiFi
 setup_wifi();

 // Подключение MQTT
 client.setServer(mqtt_server, mqtt_port);
 client.setCallback(callback);

 display.clearDisplay();
 display.println("System ready");
 display.display();
}

void setup_wifi() {
 delay(10);
 Serial.println();
 Serial.print("Connecting to ");
 Serial.println(ssid);

 WiFi.mode(WIFI_STA);
 WiFi.begin(ssid, password);

 while (WiFi.status() != WL_CONNECTED) {
 delay(500);
 Serial.print(".");
 }

 Serial.println("");
 Serial.println("WiFi connected");
 Serial.println("IP address: ");
 Serial.println(WiFi.localIP());
}

void callback(char* topic, byte* payload, unsigned int length) {
 // Обработка входящих команд
 Serial.print("Message arrived [");
 Serial.print(topic);
 Serial.print("] ");

 char message[length + 1];
 for (int i = 0; i < length; i++) {
 message[i] = (char)payload[i];
 }
 message[length] = '\0';

 Serial.println(message);

 // Парсинг JSON команды
 StaticJsonDocument<200> doc;
 DeserializationError error = deserializeJson(doc, message);

 if (error) {
 Serial.print("deserializeJson() failed: ");
 Serial.println(error.f_str());
 return;
 }

 // Пример: команда включения ИК-сигнала
 if (strcmp(topic, "home/livingroom/sensorbox_01/command") == 0) {
 const char* action = doc["action"];
 if (strcmp(action, "tv_power") == 0) {
 irsend.sendNEC(0xE0E040BF, 32);
 Serial.println("TV POWER sent");
 }
 }
}

void reconnect() {
 // Loop until we're reconnected
 while (!client.connected()) {
 Serial.print("Attempting MQTT connection...");

 String clientId = String(device_id) + "-" + String(random(0xffff), HEX);

 if (client.connect(clientId.c_str(), mqtt_user, mqtt_pass)) {
 Serial.println("connected");

 // Публикация статуса
 client.publish(topic_status, "online", true);

 // Подписка на команды
 client.subscribe("home/livingroom/sensorbox_01/command");
 } else {
 Serial.print("failed, rc=");
 Serial.print(client.state());
 Serial.println(" try again in 5 seconds");
 delay(5000);
 }
 }
}

// Чтение MQ-2 с фильтрацией
uint16_t readMQ2() {
 uint32_t sum = 0;
 for(int i=0; i<10; i++) {
 sum += analogRead(MQ2_PIN);
 delay(10);
 }
 return sum / 10; // Скользящее среднее
}

// Расчет концентрации газа (упрощенно)
float calculateGasRatio(uint16_t raw_value) {
 return (float)raw_value / (float)mq2_baseline;
}

float getGasPPM(uint16_t raw_value) {
 float ratio = calculateGasRatio(raw_value);
 // Упрощенная формула (для MQ-2)
 // В реальности нужна калибровка по графикам из даташита
 return 1000 * pow(ratio, -1.5);
}

void loop() {
 if (!client.connected()) {
 reconnect();
 }
 client.loop();

 unsigned long now = millis();
 if (now - lastMsg > 60000) { // Отправка раз в минуту
 lastMsg = now;

 // Чтение датчиков
 float temperature = dht.readTemperature();
 float humidity = dht.readHumidity();
 uint16_t mq2_raw = readMQ2();
 float gas_ppm = getGasPPM(mq2_raw);
 int rssi = WiFi.RSSI();

 // Формирование JSON
 StaticJsonDocument<256> doc;
 doc["temperature"] = temperature;
 doc["humidity"] = humidity;
 doc["mq2_raw"] = mq2_raw;
 doc["gas_ppm"] = gas_ppm;
 doc["battery_mv"] = analogReadMilliVolts(35); // Внутренний ADC
 doc["rssi"] = rssi;
 doc["uptime_sec"] = millis() / 1000;
 doc["timestamp"] = time(nullptr);

 char jsonBuffer[512];
 serializeJson(doc, jsonBuffer);

 // Публикация
 if (client.publish(topic_telemetry, jsonBuffer)) {
 Serial.println("Data published");

 // Вывод на дисплей
 display.clearDisplay();
 display.setTextSize(1);
 display.setTextColor(SSD1306_WHITE);
 display.setCursor(0,0);
 display.print("Temp: "); display.print(temperature); display.println(" C");
 display.print("Hum: "); display.print(humidity); display.println(" %");
 display.print("Gas: "); display.print(gas_ppm); display.println(" ppm");
 display.print("RSSI: "); display.print(rssi); display.println(" dBm");
 display.display();
 } else {
 Serial.println("Failed to publish");
 }
 }

 // Обработка ИК-сигналов
 decodeIR();

 delay(100);
}

