// Автоматизация: включение кондиционера при температуре >24°C
void checkTemperatureAutomation(float temp) {
 static bool ac_on = false;

 if (temp > 24.0 && !ac_on) {
 Serial.println("Temperature high, turning on AC");
 sendIRCommand(0xA05F906F); // AC POWER ON
 sendIRCommand(0xA05F10EF); // AC 22C
 ac_on = true;

 // Уведомление в MQTT
 client.publish("home/livingroom/ac/status", "on");
 }
 else if (temp < 22.0 && ac_on) {
 Serial.println("Temperature low, turning off AC");
 sendIRCommand(0xA05F906F); // AC POWER OFF
 ac_on = false;

 client.publish("home/livingroom/ac/status", "off");
 }
}
